498→    fn unique_temp_dir(prefix: &str) -> PathBuf {
499→        let nanos = SystemTime::now()
500→            .duration_since(UNIX_EPOCH)
501→            .map(|d| d.as_nanos())
502→            .unwrap_or(0);
503→        let path = std::env::temp_dir().join(format!("{prefix}-{nanos}"));
504→        std::fs::create_dir_all(&path).expect("create temp dir");
505→        path
506→    }
507→
508→    #[test]
509→    fn last_session_hint_roundtrip() {
510→        let dir = unique_temp_dir("arcan-last-session-hint");
511→        persist_last_session_hint(&dir, "session-42").expect("persist hint");
512→        assert_eq!(read_last_session_hint(&dir).as_deref(), Some("session-42"));
513→        let _ = std::fs::remove_dir_all(dir);
514→    }
515→
516→    #[tokio::test]
517→    async fn resolve_chat_session_prefers_explicit_session() {
518→        let dir = unique_temp_dir("arcan-resolve-explicit");
519→        persist_last_session_hint(&dir, "hint-session").expect("persist hint");
520→        let selected = resolve_chat_session(&dir, Some("explicit-session".to_owned())).await;
521→        assert_eq!(selected, "explicit-session");
522→        let _ = std::fs::remove_dir_all(dir);
523→    }
524→
525→    #[tokio::test]
526→    async fn resolve_chat_session_uses_last_session_hint() {
527→        let dir = unique_temp_dir("arcan-resolve-hint");
528→        persist_last_session_hint(&dir, "hint-session").expect("persist hint");
529→        let selected = resolve_chat_session(&dir, None).await;
530→        assert_eq!(selected, "hint-session");
531→        let _ = std::fs::remove_dir_all(dir);
532→    }
533→
534→    #[tokio::test]
535→    async fn most_recent_session_falls_back_to_latest_event_timestamp() {
536→        let dir = unique_temp_dir("arcan-resolve-journal");
537→        let journal_path = dir.join("journal.redb");
538→        let journal = RedbJournal::open(&journal_path).expect("open journal");
539→
540→        let mk_event = |session: &str, timestamp: u64| EventEnvelope {
541→            event_id: LagoEventId::new(),
542→            session_id: LagoSessionId::from_string(session),
543→            branch_id: LagoBranchId::from_string("main"),
544→            run_id: None,
545→            seq: 0,
546→            timestamp,
547→            parent_id: None,
548→            payload: LagoEventPayload::Message {
549→                role: "user".to_owned(),
550→                content: "hello".to_owned(),
551→                model: None,
552→                token_usage: None,
553→            },
554→            metadata: std::collections::HashMap::new(),
555→            schema_version: 1,
556→        };
557→
558→        journal
559→            .append(mk_event("session-old", 1_000))
560→            .await
561→            .expect("append old event");
562→        journal
563→            .append(mk_event("session-new", 2_000))
564→            .await
565→            .expect("append new event");
566→        drop(journal);
567→
568→        let selected = most_recent_session_from_journal(&dir)
569→            .await
570→            .expect("resolve most recent session");
571→        assert_eq!(selected.as_deref(), Some("session-new"));
572→        let _ = std::fs::remove_dir_all(dir);
573→    }
574→}
