  1→use crate::models::{AppState, UiBlock};
  2→use crate::network::{NetworkClient, NetworkConfig};
  3→use crate::ui;
  4→use arcan_core::protocol::AgentEvent;
  5→use chrono::Utc;
  6→use crossterm::event::{self, Event, KeyCode, KeyEventKind};
  7→use ratatui::{Terminal, backend::Backend};
  8→use std::sync::Arc;
  9→use std::time::Duration;
 10→use tokio::sync::mpsc;
 11→
 12→#[derive(Debug, PartialEq, Eq)]
 13→enum ModelCommand {
 14→    ShowCurrent,
 15→    Set {
 16→        provider: String,
 17→        model: Option<String>,
 18→    },
 19→}
 20→
 21→fn parse_model_command(message: &str) -> Result<Option<ModelCommand>, String> {
 22→    let trimmed = message.trim();
 23→    if !trimmed.starts_with("/model") {
 24→        return Ok(None);
 25→    }
 26→
 27→    let remainder = trimmed.trim_start_matches("/model").trim();
 28→    if remainder.is_empty() {
 29→        return Ok(Some(ModelCommand::ShowCurrent));
 30→    }
 31→
 32→    if remainder.contains(char::is_whitespace) {
 33→        return Err("Usage: /model | /model <provider> | /model <provider>:<model>".to_string());
 34→    }
 35→
 36→    if let Some((provider, model)) = remainder.split_once(':') {
 37→        if provider.is_empty() || model.is_empty() {
 38→            return Err("Usage: /model <provider>:<model> (both values are required)".to_string());
 39→        }
 40→        return Ok(Some(ModelCommand::Set {
 41→            provider: provider.to_string(),
 42→            model: Some(model.to_string()),
 43→        }));
 44→    }
 45→
 46→    Ok(Some(ModelCommand::Set {
 47→        provider: remainder.to_string(),
 48→        model: None,
 49→    }))
 50→}
 51→
 52→pub struct App {
 53→    pub state: AppState,
 54→    pub should_quit: bool,
 55→    pub client: Arc<NetworkClient>,
 56→    pub event_rx: mpsc::Receiver<AgentEvent>,
 57→}
 58→
 59→impl App {
 60→    pub fn new(config: NetworkConfig) -> Self {
 61→        let client = Arc::new(NetworkClient::new(config));
 62→        let (tx, rx) = mpsc::channel(100);
 63→
 64→        // Spawn network listener
 65→        let listener_client = client.clone();
 66→        tokio::spawn(async move {
 67→            if let Err(e) = listener_client.listen_events(tx).await {
 68→                tracing::error!("Event listener ended: {}", e);
 69→            }
 70→        });
 71→
 72→        Self {
 73→            state: AppState::new(),
 74→            should_quit: false,
 75→            client,
 76→            event_rx: rx,
 77→        }
 78→    }
 79→
 80→    fn push_system_alert(&mut self, text: impl Into<String>) {
 81→        self.state.blocks.push(UiBlock::SystemAlert {
 82→            text: text.into(),
 83→            timestamp: Utc::now(),
 84→        });
 85→    }
 86→
 87→    async fn handle_model_command(&mut self, message: &str) -> bool {
 88→        let parsed = match parse_model_command(message) {
 89→            Ok(command) => command,
 90→            Err(usage) => {
 91→                self.push_system_alert(usage);
 92→                return true;
 93→            }
 94→        };
 95→
 96→        let Some(command) = parsed else {
 97→            return false;
 98→        };
 99→
100→        match command {
101→            ModelCommand::ShowCurrent => match self.client.get_model().await {
102→                Ok(model) => self.push_system_alert(format!("Current model: {model}")),
103→                Err(err) => self.push_system_alert(format!("Failed to fetch model: {err}")),
104→            },
105→            ModelCommand::Set { provider, model } => {
106→                match self.client.set_model(&provider, model.as_deref()).await {
107→                    Ok(active_model) => {
108→                        self.push_system_alert(format!("Switched model: {active_model}"))
109→                    }
110→                    Err(err) => self.push_system_alert(format!("Failed to switch model: {err}")),
111→                }
112→            }
113→        }
114→
115→        true
116→    }
117→
118→    pub async fn run<B: Backend>(&mut self, terminal: &mut Terminal<B>) -> anyhow::Result<()> {
119→        loop {
120→            // Draw UI
121→            terminal.draw(|f| ui::draw(f, &self.state))?;
122→
123→            // Process external AgentEvents non-blocking
124→            while let Ok(event) = self.event_rx.try_recv() {
125→                self.state.apply_event(event);
126→            }
127→
128→            // Handle UI events non-blocking
129→            if event::poll(Duration::from_millis(50))? {
130→                if let Event::Key(key) = event::read()? {
131→                    if key.kind == KeyEventKind::Press {
132→                        match key.code {
133→                            KeyCode::Esc => self.should_quit = true,
134→                            KeyCode::Char('c')
135→                                if key
136→                                    .modifiers
137→                                    .contains(crossterm::event::KeyModifiers::CONTROL) =>
138→                            {
139→                                self.should_quit = true;
140→                            }
141→                            KeyCode::Char(c) => {
142→                                self.state.input_buffer.push(c);
143→                            }
144→                            KeyCode::Backspace => {
145→                                self.state.input_buffer.pop();
146→                            }
147→                            KeyCode::Enter => {
148→                                let msg = self.state.input_buffer.trim().to_string();
149→                                if !msg.is_empty() {
150→                                    if msg == "/clear" {
151→                                        self.state.blocks.clear();
152→                                        self.state.streaming_text = None;
153→                                        self.state.is_busy = false;
154→                                    } else if self.handle_model_command(&msg).await {
155→                                    } else if msg.starts_with("/approve") {
156→                                        let parts: Vec<&str> = msg.split_whitespace().collect();
157→                                        if parts.len() >= 3 {
158→                                            let approval_id = parts[1].to_string();
159→                                            let decision = match parts[2]
160→                                                .to_ascii_lowercase()
161→                                                .as_str()
162→                                            {
163→                                                "yes" | "y" | "approved" | "approve" => {
164→                                                    "approved".to_string()
165→                                                }
166→                                                "no" | "n" | "denied" | "deny" => {
167→                                                    "denied".to_string()
168→                                                }
169→                                                invalid => {
170→                                                    tracing::warn!(
171→                                                        "Invalid approval decision '{}'. Use yes/no.",
172→                                                        invalid
173→                                                    );
174→                                                    self.state.input_buffer.clear();
175→                                                    continue;
176→                                                }
177→                                            };
178→                                            let reason = if parts.len() > 3 {
179→                                                Some(parts[3..].join(" "))
180→                                            } else {
181→                                                None
182→                                            };
183→
184→                                            let submit_client = self.client.clone();
185→                                            tokio::spawn(async move {
186→                                                if let Err(e) = submit_client
187→                                                    .submit_approval(
188→                                                        &approval_id,
189→                                                        &decision,
190→                                                        reason.as_deref(),
191→                                                    )
192→                                                    .await
193→                                                {
194→                                                    tracing::error!("Submit approval error: {}", e);
195→                                                }
196→                                            });
197→                                        } else {
198→                                            tracing::warn!(
199→                                                "Invalid /approve syntax. Use: /approve <id> <yes|no> [reason]"
200→                                            );
201→                                        }
202→                                    } else {
203→                                        self.state.is_busy = true;
204→                                        self.state.blocks.push(UiBlock::HumanMessage {
205→                                            text: msg.clone(),
206→                                            timestamp: Utc::now(),
207→                                        });
208→                                        let submit_client = self.client.clone();
209→                                        tokio::spawn(async move {
210→                                            if let Err(e) =
211→                                                submit_client.submit_run(&msg, None).await
212→                                            {
213→                                                tracing::error!("Submit error: {}", e);
214→                                            }
215→                                        });
216→                                    }
217→                                    self.state.input_buffer.clear();
218→                                }
219→                            }
220→                            _ => {}
221→                        }
222→                    }
223→                }
224→            }
225→
226→            if self.should_quit {
227→                break;
228→            }
229→        }
230→        Ok(())
231→    }
232→}
