 2→use std::path::Path;
 3→use std::time::Duration;
 4→
 5→/// Check whether a daemon is already healthy at the given URL.
 6→async fn is_daemon_healthy(base_url: &str) -> bool {
 7→    let url = format!("{base_url}/health");
 8→    let client = reqwest::Client::builder()
 9→        .timeout(Duration::from_secs(2))
10→        .build();
11→    let Ok(client) = client else { return false };
12→    matches!(client.get(&url).send().await, Ok(resp) if resp.status().is_success())
13→}
14→
15→/// Ensure a daemon is running on the given port.
16→///
17→/// 1. Probe `GET /health`. If healthy, return immediately.
18→/// 2. Otherwise spawn `arcan serve` as a detached child process, writing
19→///    stdout/stderr to `{data_dir}/daemon.log` and the PID to
20→///    `{data_dir}/daemon.pid`.
21→/// 3. Poll `/health` until it succeeds (up to ~12 s).
22→pub async fn ensure_daemon(data_dir: &Path, port: u16) -> anyhow::Result<String> {
23→    let base_url = format!("http://127.0.0.1:{port}");
24→
25→    if is_daemon_healthy(&base_url).await {
26→        tracing::info!("Daemon already running on {base_url}");
27→        return Ok(base_url);
28→    }
29→
30→    tracing::info!("Starting daemon on port {port}...");
31→
32→    fs::create_dir_all(data_dir)?;
33→    let log_file = fs::File::create(data_dir.join("daemon.log"))?;
34→    let stderr_log = log_file.try_clone()?;
35→
36→    // Resolve the current executable so `arcan serve` uses the same binary.
37→    let exe = std::env::current_exe()?;
38→
39→    let child = std::process::Command::new(exe)
40→        .args([
41→            "serve",
42→            "--port",
43→            &port.to_string(),
44→            "--data-dir",
45→            &data_dir.to_string_lossy(),
46→        ])
47→        .stdout(log_file)
48→        .stderr(stderr_log)
49→        .stdin(std::process::Stdio::null())
50→        .spawn()?;
51→
52→    // Write PID for later inspection / cleanup.
53→    fs::write(data_dir.join("daemon.pid"), child.id().to_string())?;
54→
55→    // Poll health endpoint.
56→    let max_retries = 60;
57→    let delay = Duration::from_millis(200);
58→    for i in 0..max_retries {
59→        tokio::time::sleep(delay).await;
60→        if is_daemon_healthy(&base_url).await {
61→            tracing::info!("Daemon healthy after {} ms", (i + 1) * 200);
62→            return Ok(base_url);
63→        }
64→    }
65→
66→    anyhow::bail!(
67→        "Daemon failed to become healthy within {}s. Check {}/daemon.log for details.",
68→        max_retries * 200 / 1000,
69→        data_dir.display()
70→    );
71→}
