200→    fn last_assistant_message_matches(&self, text: &str) -> bool {
201→        self.blocks
202→            .last()
203→            .and_then(|block| match block {
204→                UiBlock::AssistantMessage { text, .. } => Some(text.as_str()),
205→                _ => None,
206→            })
207→            .is_some_and(|last| last == text)
208→    }
209→}
